     1→import { page } from 'vitest/browser';
     2→import { beforeEach, describe, expect, it, vi } from 'vitest';
     3→import { render } from 'vitest-browser-svelte';
     4→import Page from './+page.svelte';
     5→import { appState } from '$lib/state.svelte.js';
     6→import { md } from '$lib/types.js';
     7→
     8→describe('/+page.svelte', () => {
     9→	it('renders the selector sidebar and chat area', async () => {
    10→		render(Page);
    11→		// Chat pane: active chat heading (h2 with the selected partner's name)
    12→		await expect
    13→			.element(page.getByRole('heading', { name: 'Claudia', level: 2 }))
    14→			.toBeInTheDocument();
    15→		// Input area present
    16→		await expect.element(page.getByRole('button', { name: 'Send' })).toBeInTheDocument();
    17→	});
    18→
    19→	describe('layout', () => {
    20→		beforeEach(() => {
    21→			appState.currentlySelected = 0;
    22→			appState.chats[0].messages = [];
    23→		});
    24→
    25→		it('app is 50vw wide and 50vh tall', () => {
    26→			render(Page);
    27→			const app = document.querySelector('.app')!;
    28→			const { width, height } = app.getBoundingClientRect();
    29→			// getBoundingClientRect includes border, matching the border-box width/height
    30→			expect(width).toBeCloseTo(window.innerWidth * 0.5, 0);
    31→			expect(height).toBeCloseTo(window.innerHeight * 0.5, 0);
    32→		});
    33→
    34→		it('app is centered in the viewport', () => {
    35→			render(Page);
    36→			const app = document.querySelector('.app')!;
    37→			const { left, right, top, bottom } = app.getBoundingClientRect();
    38→			const centerX = (left + right) / 2;
    39→			const centerY = (top + bottom) / 2;
    40→			expect(Math.abs(centerX - window.innerWidth / 2)).toBeLessThanOrEqual(1);
    41→			expect(Math.abs(centerY - window.innerHeight / 2)).toBeLessThanOrEqual(1);
    42→		});
    43→
    44→		it('input is pinned to the bottom of the app container', () => {
    45→			render(Page);
    46→			const app = document.querySelector('.app')!;
    47→			const input = document.querySelector('.input')!;
    48→			const { bottom: appBottom } = app.getBoundingClientRect();
    49→			const { bottom: inputBottom } = input.getBoundingClientRect();
    50→			// Allow 1px for sub-pixel rounding
    51→			expect(Math.abs(appBottom - inputBottom)).toBeLessThanOrEqual(1);
    52→		});
    53→
    54→		it('app stays within viewport when messages overflow', async () => {
    55→			for (let i = 0; i < 30; i++) {
    56→				appState.chats[0].messages.push({
    57→					role: 'user',
    58→					text: md(`Message ${i}`),
    59→					time: new Date()
    60→				});
    61→			}
    62→			render(Page);
    63→			const app = document.querySelector('.app')!;
    64→			// .chat ul — not .selector ul which comes first in the DOM
    65→			const msgList = document.querySelector('.chat ul')!;
    66→			// App must not grow a scrollbar — content scrolls inside, not outside
    67→			expect(app.scrollHeight).toBe(app.clientHeight);
    68→			// The message list itself is the scrollable container
    69→			expect(msgList.scrollHeight).toBeGreaterThan(msgList.clientHeight);
    70→		});
    71→
    72→		it('auto-scrolls to the bottom when messages overflow', async () => {
    73→			for (let i = 0; i < 30; i++) {
    74→				appState.chats[0].messages.push({
    75→					role: 'user',
    76→					text: md(`Message ${i}`),
    77→					time: new Date()
    78→				});
    79→			}
    80→			render(Page);
    81→			// Wait for the scroll $effect to fire and settle.
    82→			// Both assertions needed: overflow proves the list is actually scrollable;
    83→			// scrollTop proximity proves the scroll $effect ran correctly.
    84→			await vi.waitFor(() => {
    85→				const msgList = document.querySelector('.chat ul')!;
    86→				expect(msgList.scrollHeight).toBeGreaterThan(msgList.clientHeight);
    87→				expect(msgList.scrollHeight - msgList.scrollTop - msgList.clientHeight).toBeLessThan(16);
    88→			});
    89→		});
    90→	});
    91→});
    92→

