     1→<script lang="ts">
     2→	import { appState } from '../state.svelte.js';
     3→	import { formatTime } from '../time.js';
     4→
     5→	const chat = $derived(appState.chats[appState.currentlySelected]);
     6→
     7→	let messagesEl: HTMLUListElement = $state()!;
     8→
     9→	// Scroll-lock: true = auto-follow new messages. Captured before DOM changes
    10→	// to avoid post-update timing issues.
    11→	let scrollLocked = true;
