     1→/** Format a message time: HH:MM if today, else "Mon DD". */
     2→export function formatTime(date: Date): string {
     3→	const now = new Date();
     4→	const sameDay =
     5→		date.getFullYear() === now.getFullYear() &&
     6→		date.getMonth() === now.getMonth() &&
     7→		date.getDate() === now.getDate();
     8→	if (sameDay) {
     9→		return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    10→	}
    11→	return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
    12→}
