### Step 2 — Create `src/test-utils/arb.ts`

This file is the single source of truth for all test data generation. It mirrors every type in `src/lib/types.ts`.

Full implementation:

```typescript
/**
 * fast-check arbitraries for all game types.
 *
 * Design notes:
 * - arbMarkdown wraps fc.stringOf(fc.alphanumeric()) so generated strings contain
 *   no HTML special characters, emoji, or regex metacharacters — making
 *   page.getByText() queries reliable in browser tests.
 * - We use fc.sample(arb, 1)[0] at call sites (single draw), not fc.assert().
 *   Browser rendering tests are too slow for multi-run property checking; the
 *   goal is data-independence, not exhaustive enumeration.
 */
import * as fc from 'fast-check';
import { md, type ChatComponentState, type ChatUser, type ChatAppState } from '$lib/types.js';

// Union of all four status values
export const arbStatus = (): fc.Arbitrary<ChatUser['status']> =>
    fc.constantFrom('active', 'away', 'busy', 'offline');

// Safe alphanumeric Markdown — no HTML chars, no emoji, works with getByText()
export const arbMarkdown = () =>
    fc.stringOf(fc.alphanumeric(), { minLength: 3, maxLength: 20 }).map(md);

export const arbChatUser = (): fc.Arbitrary<ChatUser> =>
    fc.record({
        name:           fc.stringOf(fc.alpha(), { minLength: 3, maxLength: 12 }),
        profilePicture: fc.constant(''),
        status:         arbStatus(),
        statusText:     arbMarkdown(),
    });

const arbMessage = () =>
    fc.record({
        role: fc.constantFrom('user' as const, 'partner' as const),
        text: arbMarkdown(),
        time: fc.date({ min: new Date('2024-01-01'), max: new Date('2026-12-31') }),
    });

/**
 * Generates a ChatComponentState.
 * @param minMessages - minimum number of messages (default 0)
 */
export const arbChat = (minMessages = 0): fc.Arbitrary<ChatComponentState> =>
    fc.record({
        name:           fc.stringOf(fc.alpha(), { minLength: 3, maxLength: 12 }),
        profilePicture: fc.constant(''),
        status:         arbStatus(),
        statusText:     arbMarkdown(),
        messages:       fc.array(arbMessage(), { minLength: minMessages, maxLength: 6 }),
    });

/**
 * Generates a ChatComponentState whose last message is guaranteed to be from
 * the partner role. Used by Selector tests that assert on partner preview text.
 */
export const arbChatWithPartnerLastMessage = (): fc.Arbitrary<ChatComponentState> =>
    arbChat(0).chain(chat =>
        fc.record({
            role: fc.constant('partner' as const),
            text: arbMarkdown(),
            time: fc.date({ min: new Date('2024-01-01'), max: new Date('2026-12-31') }),
        }).map(partnerMsg => ({
            ...chat,
            messages: [...chat.messages, partnerMsg],
        }))
    );

/**
 * Generates a full ChatAppState.
 * Uses .chain() to constrain currentlySelected to a valid index into chats[].
 *
 * @param minChats - minimum number of chats (default 2, enough for switching tests)
 */
export const arbAppState = (minChats = 2): fc.Arbitrary<ChatAppState> =>
    fc.array(arbChat(), { minLength: minChats, maxLength: 6 }).chain(chats =>
        fc.record({
            chats:             fc.constant(chats),
            player:            arbChatUser(),
            currentlySelected: fc.integer({ min: 0, max: chats.length - 1 }),
        })
    );
```

Key design decisions:

- `fc.alphanumeric()` is available as `fc.alphanumeric` in fast-check v3+. If the installed version only has `fc.char()` / `fc.ascii()`, use `fc.stringOf(fc.char().filter(c => /[a-zA-Z0-9]/.test(c)), ...)` instead — but fast-check 3.x ships `fc.alphanumeric()` natively.
- `profilePicture: fc.constant('')` — the components gracefully handle empty-string image src (renders with `background: #ccc`), so blank is correct.
- `arbChatWithPartnerLastMessage` is kept separate rather than baked into `arbChat`, because most tests do not need this constraint and keeping it separate keeps `arbChat` simple.
- `.chain()` in `arbAppState` is the canonical fast-check idiom for cross-field constraints (here: making `currentlySelected` depend on `chats.length`).
- `arbMessage` is not exported — it is only composed internally into `arbChat`.

